import React, { useState, useEffect } from 'react';
import { dishAPI, restaurantAPI } from '../services/api';
import { motion } from 'framer-motion';

const CustomerDashboard = ({ user, onLogout }) => {
  const [restaurants, setRestaurants] = useState([]);
  const [selectedRestaurant, setSelectedRestaurant] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [filteredRestaurants, setFilteredRestaurants] = useState([]);
  const [showMenu, setShowMenu] = useState({});

  useEffect(() => {
    loadRestaurants();
  }, []);

  useEffect(() => {
    filterRestaurants();
  }, [restaurants, searchTerm, filterType]);

  const loadRestaurants = async () => {
    try {
      const response = await restaurantAPI.getAll();
      setRestaurants(response.data);
    } catch (error) {
      console.error('Error loading restaurants:', error);
    }
  };

  const filterRestaurants = () => {
    let filtered = restaurants;

    if (searchTerm) {
      filtered = filtered.filter(restaurant => 
        restaurant.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        restaurant.address?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (filterType === 'veg') {
      filtered = filtered.filter(r => r.veg && !r.nonVeg);
    } else if (filterType === 'nonveg') {
      filtered = filtered.filter(r => r.nonVeg);
    }

    setFilteredRestaurants(filtered);
  };

  const toggleMenu = (restaurantId) => {
    setShowMenu(prev => ({
      ...prev,
      [restaurantId]: !prev[restaurantId]
    }));
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-md sticky top-0 z-50">
        <div className="flex justify-between items-center px-8 py-4">
          <h1 className="text-2xl font-bold">🍔 SnackSmart</h1>
          <div className="flex items-center gap-4">
            <span>Welcome, {user.username}!</span>
            <button 
              onClick={onLogout}
              className="bg-red-500 hover:bg-red-600 transition px-4 py-2 rounded-lg"
            >
              Logout
            </button>
          </div>
        </div>
      </header>

      <div className="container mx-auto p-6">
        {/* Search Bar */}
        <div className="flex gap-3 items-center mb-8">
          <input
            type="text"
            placeholder="Search restaurants by name or location..."
            className="flex-1 border rounded-xl p-3 shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <select 
            className="border rounded-xl p-3 shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
            value={filterType}
            onChange={(e) => setFilterType(e.target.value)}
          >
            <option value="all">All</option>
            <option value="veg">Veg Only</option>
            <option value="nonveg">Non-Veg Only</option>
          </select>
        </div>

        {/* Restaurant Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredRestaurants.map((r) => (
            <motion.div 
              key={r.id} 
              initial={{ opacity: 0, y: 30 }} 
              animate={{ opacity: 1, y: 0 }} 
              transition={{ duration: 0.4 }}
              className="bg-white rounded-2xl shadow-lg hover:shadow-2xl transition transform hover:-translate-y-1"
            >
              <img
                src={r.imageUrl || '/default-restaurant.jpg'}
                alt={r.name}
                className="h-40 w-full object-cover rounded-t-2xl"
                onError={(e) => {
                  e.target.src = 'https://via.placeholder.com/400x200/f3f4f6/9ca3af?text=Restaurant';
                }}
              />
              <div className="p-4">
                <h2 className="text-xl font-semibold">{r.name}</h2>
                <p className="text-gray-500">{r.address}</p>
                <p className="mt-1 text-sm text-gray-700">
                  📞 {r.phone} • ⭐ {r.rating || 0}/5
                </p>
                <p className="mt-1">
                  {r.veg && r.nonVeg ? "🌿🍗 Veg & Non-Veg" : r.veg ? "🌿 Veg" : "🍗 Non-Veg"}
                </p>
                <button 
                  onClick={() => toggleMenu(r.id)}
                  className="mt-4 w-full bg-blue-500 text-white py-2 rounded-lg hover:bg-blue-600 transition"
                >
                  {showMenu[r.id] ? 'Hide Menu' : 'View Menu →'}
                </button>

                {/* Menu Display */}
                {showMenu[r.id] && (
                  <motion.div 
                    initial={{ opacity: 0, height: 0 }}
                    animate={{ opacity: 1, height: 'auto' }}
                    className="mt-4 border-t pt-4"
                  >
                    <h3 className="font-semibold mb-2">Menu</h3>
                    {r.menu && r.menu.length > 0 ? (
                      <div className="space-y-2">
                        {r.menu.map((dish, index) => (
                          <div key={index} className="flex justify-between items-center p-2 bg-gray-50 rounded">
                            <div>
                              <span className="font-medium">{dish.dishName}</span>
                              <span className="ml-2 text-xs">
                                {dish.veg ? '🌿' : '🍗'}
                              </span>
                            </div>
                            <span className="font-semibold text-green-600">₹{dish.price}</span>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-gray-500 text-sm">No menu items available</p>
                    )}
                  </motion.div>
                )}
              </div>
            </motion.div>
          ))}
        </div>

        {filteredRestaurants.length === 0 && (
          <div className="text-center py-8">
            <p className="text-gray-500">No restaurants found.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default CustomerDashboard;
